{
  "mode": "method",
  "tests": [
    {
      "name": "valid_sub_page_configuration",
      "input": {
        "subPage": {
          "title": "Challenge Details",
          "url": "/challenges/details",
          "icon": "details"
        }
      },
      "output": {
        "status": "success",
        "message": "Sub page configured successfully."
      },
      "notes": "Validates that a standard sub page configuration is accepted."
    },
    {
      "name": "duplicate_sub_page_identifier",
      "input": {
        "subPage": {
          "title": "Challenge Details",
          "url": "/challenges/details",
          "icon": "details"
        }
      },
      "output": {
        "status": "error",
        "message": "Sub page identifier already exists."
      },
      "notes": "Tests handling of duplicate identifiers."
    },
    {
      "name": "missing_title",
      "input": {
        "subPage": {
          "url": "/challenges/details",
          "icon": "details"
        }
      },
      "output": {
        "status": "error",
        "message": "Title is required."
      },
      "notes": "Ensures that title is a mandatory field."
    },
    {
      "name": "invalid_url_format",
      "input": {
        "subPage": {
          "title": "Challenge Details",
          "url": "invalid-url",
          "icon": "details"
        }
      },
      "output": {
        "status": "error",
        "message": "Invalid URL format."
      },
      "notes": "Checks validation of URL format."
    },
    {
      "name": "empty_sub_page_configuration",
      "input": {
        "subPage": {}
      },
      "output": {
        "status": "error",
        "message": "Sub page configuration cannot be empty."
      },
      "notes": "Tests response to completely empty configuration."
    },
    {
      "name": "long_title_exceeds_limit",
      "input": {
        "subPage": {
          "title": "A very long title that exceeds the maximum allowed length for a sub page title",
          "url": "/challenges/details",
          "icon": "details"
        }
      },
      "output": {
        "status": "error",
        "message": "Title exceeds maximum length."
      },
      "notes": "Validates title length constraints."
    },
    {
      "name": "valid_sub_page_with_icon",
      "input": {
        "subPage": {
          "title": "Challenge Overview",
          "url": "/challenges/overview",
          "icon": "overview"
        }
      },
      "output": {
        "status": "success",
        "message": "Sub page configured successfully."
      },
      "notes": "Tests configuration with a valid icon."
    },
    {
      "name": "unsupported_icon_type",
      "input": {
        "subPage": {
          "title": "Challenge Details",
          "url": "/challenges/details",
          "icon": "unsupported_icon"
        }
      },
      "output": {
        "status": "error",
        "message": "Icon type is not supported."
      },
      "notes": "Checks handling of unsupported icon types."
    }
  ],
  "assumptions": "Sub page identifiers must be unique and follow specific formatting rules.",
  "notes": "Ensure to test edge cases for input validation."
}
